import "dotenv/config"
import { PrismaClient } from "@prisma/client"

const prisma = new PrismaClient()

type CollectionSeed = {
  name: string
  slug: string
  description: string
  isPublic: boolean
  isFeatured: boolean
  color: string
  toolSlugs: string[]
}

const defaultCollections: CollectionSeed[] = [
  {
    name: "Best Free AI Tools",
    slug: "best-free-ai-tools",
    description: "High-quality AI tools that offer generous free tiers. Perfect for getting started with AI without spending a dime.",
    isPublic: true,
    isFeatured: true,
    color: "#10b981",
    toolSlugs: ["chatgpt", "claude", "grammarly-go", "photomath", "quillbot"],
  },
  {
    name: "AI for Developers",
    slug: "ai-for-developers",
    description: "Essential AI tools for software developers. From code completion to debugging, these tools will boost your productivity.",
    isPublic: true,
    isFeatured: true,
    color: "#3b82f6",
    toolSlugs: ["github-copilot", "cursor", "tabnine", "anthropic-code", "codeium"],
  },
  {
    name: "AI Image Generators",
    slug: "ai-image-generators",
    description: "Create stunning images with AI. From art to marketing visuals, these tools bring your imagination to life.",
    isPublic: true,
    isFeatured: false,
    color: "#8b5cf6",
    toolSlugs: ["midjourney", "dall-e", "stable-diffusion", "adobe-firefly", "leonardo-ai"],
  },
  {
    name: "AI Writing Assistants",
    slug: "ai-writing-assistants",
    description: "Write better, faster with AI. Whether you're crafting emails, blog posts, or marketing copy.",
    isPublic: true,
    isFeatured: false,
    color: "#f59e0b",
    toolSlugs: ["jasper", "copy-ai", "writesonic", "anyword", "peppertype"],
  },
  {
    name: "Web3 & Crypto AI Tools",
    slug: "web3-crypto-ai",
    description: "AI tools specifically useful for Web3 developers, crypto traders, and blockchain enthusiasts.",
    isPublic: true,
    isFeatured: false,
    color: "#14b8a6",
    toolSlugs: ["chatgpt", "claude", "nifty-apps", "cryptocupid", "web3growth"],
  },
]

async function main() {
  console.log("⏳ Seeding collections...")

  try {
    let totalToolsAdded = 0

    for (const collectionData of defaultCollections) {
      const { toolSlugs, ...collectionFields } = collectionData

      // Create or update collection
      const collection = await prisma.toolCollection.upsert({
        where: { slug: collectionFields.slug },
        update: collectionFields,
        create: collectionFields,
      })

      console.log(`  📁 Collection: ${collection.name} (${collection.slug})`)

      // Find tools by slug
      const tools = await prisma.aITool.findMany({
        where: { slug: { in: toolSlugs } },
        select: { id: true, name: true, slug: true },
      })

      const foundSlugs = new Set(tools.map((t) => t.slug))
      const missingSlugs = toolSlugs.filter((s) => !foundSlugs.has(s))

      if (missingSlugs.length > 0) {
        console.log(`    ⚠️  Tools not found: ${missingSlugs.join(", ")}`)
      }

      // Add tools to collection
      for (let i = 0; i < tools.length; i++) {
        const tool = tools[i]
        await prisma.toolCollectionItem.upsert({
          where: {
            collectionId_toolId: {
              collectionId: collection.id,
              toolId: tool.id,
            },
          },
          update: { order: i },
          create: {
            collectionId: collection.id,
            toolId: tool.id,
            order: i,
          },
        })
        totalToolsAdded++
      }

      console.log(`    ✅ Added ${tools.length} tools to collection`)
    }

    // Get final count
    const collectionCount = await prisma.toolCollection.count()
    const itemCount = await prisma.toolCollectionItem.count()

    console.log(`\n✅ Successfully seeded collections`)
    console.log(`📊 Total collections: ${collectionCount}`)
    console.log(`📊 Total collection items: ${itemCount}`)
  } catch (error) {
    console.error("❌ Error seeding collections:", error)
    process.exit(1)
  } finally {
    await prisma.$disconnect()
  }
}

main()

"use client"

import { useState, useEffect, useCallback } from "react"
import Link from "next/link"
import { useSearchParams, useRouter } from "next/navigation"
import { Star, Copy, Share2, Sparkles, X, Check, ArrowRight } from "lucide-react"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Skeleton } from "@/components/ui/skeleton"

interface ToolData {
  id: string
  name: string
  slug: string
  tagline: string
  category: string
  pricing: string
  pricingModel: string
  rating: number
  reviews: number
  features: string[]
  pros: string[]
  cons: string[]
  affiliateUrl: string | null
  imageUrl: string | null
  featured: boolean
  hasFreeTrial: boolean
  hasApiAccess: boolean
  multiLanguage: boolean
  affiliateAvailable: boolean
}

type ToolDataKey = keyof ToolData

interface Criteria {
  key: ToolDataKey
  label: string
  format: (value: unknown) => string
}

const COMPARISON_CRITERIA: Criteria[] = [
  { key: "rating", label: "Overall Rating", format: (v) => `${v} ⭐` },
  { key: "pricing", label: "Pricing", format: (v) => String(v) },
  { key: "pricingModel", label: "Pricing Model", format: (v) => String(v) },
  { key: "category", label: "Category", format: (v) => String(v) },
  { key: "hasFreeTrial", label: "Free Trial", format: (v) => (v ? "Yes" : "No") },
  { key: "hasApiAccess", label: "API Access", format: (v) => (v ? "Yes" : "No") },
  { key: "multiLanguage", label: "Multi-language Support", format: (v) => (v ? "Yes" : "No") },
  { key: "affiliateAvailable", label: "Affiliate Available", format: (v) => (v ? "Yes" : "No") },
]

function getToolValue(tool: ToolData, key: ToolDataKey): unknown {
  return tool[key]
}

export default function CompareToolsPage() {
  const searchParams = useSearchParams()
  const router = useRouter()
  const [tools, setTools] = useState<ToolData[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [aiSummary, setAiSummary] = useState<string | null>(null)
  const [aiLoading, setAiLoading] = useState(false)
  const [copied, setCopied] = useState(false)
  const [showShareToast, setShowShareToast] = useState(false)

  const slugs = searchParams.get("slugs")?.split(",").filter(Boolean).slice(0, 3) ?? []

  const fetchTools = useCallback(async () => {
    if (slugs.length === 0) {
      setLoading(false)
      return
    }

    setLoading(true)
    setError(null)

    try {
      const response = await fetch("/api/tools/compare", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ toolSlugs: slugs }),
      })

      if (!response.ok) {
        throw new Error("Failed to fetch tools")
      }

      const data = await response.json()
      setTools(data.tools)
    } catch (err) {
      setError(err instanceof Error ? err.message : "An error occurred")
    } finally {
      setLoading(false)
    }
  }, [slugs])

  useEffect(() => {
    fetchTools()
  }, [fetchTools])

  const generateAiSummary = async () => {
    if (tools.length < 2) return

    setAiLoading(true)
    setAiSummary(null)

    try {
      const response = await fetch("/api/admin/ai/generate", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          action: "summarize",
          provider: "openai",
          content: buildComparisonPrompt(tools),
          language: "id",
        }),
      })

      if (!response.ok) {
        throw new Error("Failed to generate AI summary")
      }

      const reader = response.body?.getReader()
      const decoder = new TextDecoder()
      let summaryText = ""

      if (reader) {
        while (true) {
          const { done, value } = await reader.read()
          if (done) break
          summaryText += decoder.decode(value, { stream: true })
        }
      }

      setAiSummary(summaryText.replace(/\[ERROR\].*/g, "").trim())
    } catch {
      setAiSummary("Gagal menghasilkan ringkasan. Silakan coba lagi.")
    } finally {
      setAiLoading(false)
    }
  }

  const copyComparison = () => {
    const markdown = buildMarkdownTable(tools)
    navigator.clipboard.writeText(markdown)
    setCopied(true)
    setTimeout(() => setCopied(false), 2000)
  }

  const shareComparison = async () => {
    const url = `${window.location.origin}/ai-tools/compare?slugs=${slugs.join(",")}`
    try {
      await navigator.clipboard.writeText(url)
      setShowShareToast(true)
      setTimeout(() => setShowShareToast(false), 2000)
    } catch {
      router.push(`/ai-tools/compare?slugs=${slugs.join(",")}`)
    }
  }

  const clearAll = () => {
    router.push("/ai-tools")
  }

  const popularTools = [
    { name: "ChatGPT", slug: "chatgpt" },
    { name: "Claude", slug: "claude" },
    { name: "Midjourney", slug: "midjourney" },
  ]

  return (
    <div className="space-y-6">
      <div className="flex items-start justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Compare AI Tools</h1>
          <p className="mt-1 text-muted-foreground">
            Bandingkan fitur, harga, dan spesifikasi berbagai AI tools
          </p>
        </div>
        {tools.length > 0 && (
          <div className="flex gap-2">
            <Button variant="outline" size="sm" onClick={copyComparison}>
              {copied ? <Check className="mr-2 h-4 w-4" /> : <Copy className="mr-2 h-4 w-4" />}
              {copied ? "Copied!" : "Copy"}
            </Button>
            <Button variant="outline" size="sm" onClick={shareComparison}>
              <Share2 className="mr-2 h-4 w-4" />
              Share
            </Button>
            <Button variant="ghost" size="sm" onClick={clearAll}>
              <X className="mr-2 h-4 w-4" />
              Clear
            </Button>
          </div>
        )}
      </div>

      {showShareToast && (
        <div className="rounded-lg bg-green-100 px-4 py-2 text-sm text-green-800 dark:bg-green-900 dark:text-green-100">
          Link copied to clipboard!
        </div>
      )}

      {loading && (
        <div className="space-y-4">
          <Skeleton className="h-12 w-full" />
          <Skeleton className="h-64 w-full" />
        </div>
      )}

      {error && (
        <Card className="border-red-200 dark:border-red-900">
          <CardContent className="pt-6">
            <p className="text-sm text-red-600 dark:text-red-400">{error}</p>
          </CardContent>
        </Card>
      )}

      {!loading && tools.length < 2 && !error && (
        <Card>
          <CardHeader>
            <CardTitle>Select Tools to Compare</CardTitle>
            <CardDescription>
              Pilih minimal 2 AI tools untuk memulai perbandingan. Berikut saran tools populer:
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="flex flex-wrap gap-2">
              {popularTools.map((tool) => (
                <Badge
                  key={tool.slug}
                  variant="secondary"
                  className="cursor-pointer hover:bg-primary/10"
                  onClick={() => {
                    const newSlugs = [...new Set([...slugs, tool.slug])].slice(0, 3)
                    router.push(`/ai-tools/compare?slugs=${newSlugs.join(",")}`)
                  }}
                >
                  {tool.name}
                </Badge>
              ))}
            </div>
            <Link
              href="/ai-tools"
              className="inline-flex items-center text-sm text-primary hover:underline"
            >
              Browse all AI tools <ArrowRight className="ml-1 h-4 w-4" />
            </Link>
          </CardContent>
        </Card>
      )}

      {!loading && tools.length >= 2 && (
        <>
          {/* JSON-LD for comparison page */}
          <script
            id="compare-tools-jsonld"
            type="application/ld+json"
            dangerouslySetInnerHTML={{
              __html: JSON.stringify({
                "@context": "https://schema.org",
                "@type": "ItemList",
                itemListElement: tools.map((tool, index) => ({
                  "@type": "ListItem",
                  position: index + 1,
                  name: tool.name,
                  url: `${process.env.NEXT_PUBLIC_BASE_URL ?? "https://ai3.my.id"}/ai-tools/${tool.slug}`,
                  description: tool.tagline,
                })),
                numberOfItems: tools.length,
              }),
            }}
          />

          {/* AI Summary Section */}
          <Card className="border-primary/20 bg-primary/5">
            <CardHeader className="pb-3">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Sparkles className="h-5 w-5 text-primary" />
                  <CardTitle className="text-lg">AI-Powered Comparison</CardTitle>
                </div>
                <Button
                  size="sm"
                  onClick={generateAiSummary}
                  disabled={aiLoading}
                >
                  {aiLoading ? (
                    <>
                      <span className="mr-2 animate-spin">&#x27F3;</span>
                      Generating...
                    </>
                  ) : (
                    <>
                      <Sparkles className="mr-2 h-4 w-4" />
                      Generate Summary
                    </>
                  )}
                </Button>
              </div>
            </CardHeader>
            {aiSummary && (
              <CardContent>
                <div className="prose prose-sm dark:prose-invert max-w-none">
                  <p className="whitespace-pre-wrap text-sm">{aiSummary}</p>
                </div>
              </CardContent>
            )}
            {aiLoading && !aiSummary && (
              <CardContent>
                <Skeleton className="h-20 w-full" />
                <p className="mt-2 text-xs text-muted-foreground">
                  Generating AI-powered comparison summary...
                </p>
              </CardContent>
            )}
          </Card>

          {/* Comparison Table */}
          <div className="overflow-x-auto rounded-lg border">
            <table className="w-full min-w-[700px] text-sm">
              <thead className="bg-muted/50">
                <tr>
                  <th className="px-4 py-3 text-left font-medium">Metric</th>
                  {tools.map((tool) => (
                    <th key={tool.id} className="px-4 py-3 text-left">
                      <div className="flex items-center gap-2">
                        {tool.featured && <Badge variant="default" className="text-xs">Featured</Badge>}
                        <span className="font-semibold">{tool.name}</span>
                      </div>
                      <p className="mt-1 text-xs font-normal text-muted-foreground line-clamp-2">
                        {tool.tagline}
                      </p>
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {COMPARISON_CRITERIA.map((criteria, idx) => (
                  <tr key={criteria.key} className={idx > 0 ? "border-t" : ""}>
                    <td className="px-4 py-3 font-medium">{criteria.label}</td>
                    {tools.map((tool) => {
                      const value = getToolValue(tool, criteria.key)
                      return (
                        <td key={tool.id} className="px-4 py-3">
                          {criteria.format(value)}
                        </td>
                      )
                    })}
                  </tr>
                ))}
                {/* Features Row */}
                <tr className="border-t">
                  <td className="px-4 py-3 font-medium">Features</td>
                  {tools.map((tool) => (
                    <td key={tool.id} className="px-4 py-3">
                      <div className="flex flex-wrap gap-1">
                        {tool.features.map((f) => (
                          <Badge key={f} variant="outline" className="text-xs">
                            {f}
                          </Badge>
                        ))}
                      </div>
                    </td>
                  ))}
                </tr>
                {/* Rating Stars Row */}
                <tr className="border-t">
                  <td className="px-4 py-3 font-medium">Rating</td>
                  {tools.map((tool) => (
                    <td key={tool.id} className="px-4 py-3">
                      <div className="flex items-center gap-1">
                        <Star className="h-4 w-4 fill-amber-500 text-amber-500" />
                        <span className="font-medium">{tool.rating.toFixed(1)}</span>
                        <span className="text-xs text-muted-foreground">
                          ({tool.reviews} reviews)
                        </span>
                      </div>
                    </td>
                  ))}
                </tr>
                {/* Website Row */}
                <tr className="border-t">
                  <td className="px-4 py-3 font-medium">Visit</td>
                  {tools.map((tool) => (
                    <td key={tool.id} className="px-4 py-3">
                      {tool.affiliateUrl ? (
                        <a
                          href={tool.affiliateUrl}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="inline-flex items-center text-primary hover:underline"
                        >
                          Visit Website &#x2192;
                        </a>
                      ) : (
                        <Link
                          href={`/ai-tools/${tool.slug}`}
                          className="text-primary hover:underline"
                        >
                          View Details &#x2192;
                        </Link>
                      )}
                    </td>
                  ))}
                </tr>
              </tbody>
            </table>
          </div>

          {/* Pros & Cons Section */}
          <div className="grid gap-6 md:grid-cols-2">
            {tools.map((tool) => (
              <Card key={tool.id}>
                <CardHeader className="pb-3">
                  <CardTitle className="text-lg">{tool.name}</CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div>
                    <h4 className="mb-2 text-sm font-semibold text-green-600 dark:text-green-400">
                      &#x2713; Pros
                    </h4>
                    {tool.pros.length > 0 ? (
                      <ul className="space-y-1 text-sm">
                        {tool.pros.map((pro, i) => (
                          <li key={i} className="flex items-start gap-2">
                            <span className="text-green-500">&#x2022;</span>
                            {pro}
                          </li>
                        ))}
                      </ul>
                    ) : (
                      <p className="text-sm text-muted-foreground">
                        No pros listed yet.
                      </p>
                    )}
                  </div>
                  <div>
                    <h4 className="mb-2 text-sm font-semibold text-red-600 dark:text-red-400">
                      &#x2717; Cons
                    </h4>
                    {tool.cons.length > 0 ? (
                      <ul className="space-y-1 text-sm">
                        {tool.cons.map((con, i) => (
                          <li key={i} className="flex items-start gap-2">
                            <span className="text-red-500">&#x2022;</span>
                            {con}
                          </li>
                        ))}
                      </ul>
                    ) : (
                      <p className="text-sm text-muted-foreground">
                        No cons listed yet.
                      </p>
                    )}
                  </div>
                  <Link
                    href={`/ai-tools/${tool.slug}`}
                    className="inline-flex items-center text-sm text-primary hover:underline"
                  >
                    View full details &#x2192;
                  </Link>
                </CardContent>
              </Card>
            ))}
          </div>
        </>
      )}
    </div>
  )
}

function buildComparisonPrompt(tools: ToolData[]): string {
  const toolList = tools
    .map(
      (t, i) =>
        `${i + 1}. ${t.name} (${t.category})\n   - Rating: ${t.rating}/5\n   - Pricing: ${t.pricing}\n   - Features: ${t.features.join(", ") || "N/A"}\n   - Free Trial: ${t.hasFreeTrial ? "Yes" : "No"}\n   - API Access: ${t.hasApiAccess ? "Yes" : "No"}\n   - Multi-language: ${t.multiLanguage ? "Yes" : "No"}`
    )
    .join("\n\n")

  return `Bandingkan ${tools.length} AI tools berikut secara objektif dalam Bahasa Indonesia:

${toolList}

Buat ringkasan perbandingan yang mencakup:
1. Tool mana yang terbaik untuk use case tertentu
2. Perbandingan harga dan nilai
3. Strengths dan weaknesses masing-masing tool
4. Rekomendasi untuk pengguna berbeda (pemula, profesional, bisnis)

Format output dalam Markdown.`
}

function buildMarkdownTable(tools: ToolData[]): string {
  const headers = ["Metric", ...tools.map((t) => t.name)]
  const rows = [
    ["Category", ...tools.map((t) => t.category)],
    ["Pricing", ...tools.map((t) => t.pricing)],
    ["Rating", ...tools.map((t) => `${t.rating}/5`)],
    ["Free Trial", ...tools.map((t) => (t.hasFreeTrial ? "Yes" : "No"))],
    ["API Access", ...tools.map((t) => (t.hasApiAccess ? "Yes" : "No"))],
    ["Multi-language", ...tools.map((t) => (t.multiLanguage ? "Yes" : "No"))],
    [
      "Features",
      ...tools.map((t) => t.features.join(", ") || "N/A"),
    ],
  ]

  const colWidths = headers.map((h, i) =>
    Math.max(h.length, ...rows.map((r) => String(r[i]).length))
  )

  const formatRow = (cells: string[]) =>
    `| ${cells.map((c, i) => c.padEnd(colWidths[i])).join(" | ")} |`

  const separator = `| ${colWidths.map((w) => "-".repeat(w)).join(" | ")} |`

  return [
    `# AI Tools Comparison`,
    "",
    formatRow(headers),
    separator,
    ...rows.map(formatRow),
    "",
    `Generated from AI3 - AI Tools Directory`,
  ].join("\n")
}

import { AdSlot } from "@/components/ads/ad-slot"
import { InternalLinksBlock } from "@/components/layout/internal-links"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { prisma } from "@/lib/prisma"
import { generateSeo } from "@/lib/seo"
import { Search, Star, X, GitCompare, SlidersHorizontal, TrendingUp, Crown, Zap } from "lucide-react"
import type { Metadata } from "next"
import Link from "next/link"

export const dynamic = "force-dynamic"

export const metadata: Metadata = generateSeo({
  title: "AI Tools Directory",
  description: "Koleksi tools AI terbaik untuk produktivitas dan kreativitas.",
  type: "website",
  canonical: "/ai-tools",
})

const PLATFORM_OPTIONS = ["web", "ios", "android", "desktop", "api"]
const PRICING_TYPES = [
  { value: "FREE", label: "Free" },
  { value: "FREEMIUM", label: "Freemium" },
  { value: "PAID", label: "Paid" },
  { value: "SUBSCRIPTION", label: "Subscription" },
]
const SORT_OPTIONS = [
  { value: "rating", label: "⭐ Rating Tertinggi" },
  { value: "trending", label: "🔥 Trending" },
  { value: "newest", label: "🕐 Terbaru" },
  { value: "name", label: "🔤 Nama A–Z" },
  { value: "views", label: "👁️ Paling Dilihat" },
]

export default async function AiToolsPage({
  searchParams,
}: {
  searchParams: Promise<{
    q?: string
    category?: string
    pricingType?: string
    platform?: string
    hasFreeTrial?: string
    hasApiAccess?: string
    sort?: string
    compare?: string
  }>
}) {
  const { q, category, pricingType, platform, hasFreeTrial, hasApiAccess, sort, compare } = await searchParams

  // Unlimited compare
  const compareSlugs = (compare ?? "").split(",").filter(Boolean)
  const maxCompare = 20

  // Build dynamic WHERE clause
  const where: Record<string, unknown> = { AND: [] }

  if (q) {
    ;(where.AND as unknown[]).push({ name: { contains: q, mode: "insensitive" } })
  }

  if (category) {
    ;(where.AND as unknown[]).push({ category: { contains: category, mode: "insensitive" } })
  }

  if (pricingType) {
    ;(where.AND as unknown[]).push({ pricingType: pricingType as "FREE" | "FREEMIUM" | "PAID" | "SUBSCRIPTION" })
  }

  if (platform) {
    ;(where.AND as unknown[]).push({ platforms: { has: platform } })
  }

  if (hasFreeTrial === "true") {
    ;(where.AND as unknown[]).push({ hasFreeTrial: true })
  }

  if (hasApiAccess === "true") {
    ;(where.AND as unknown[]).push({ hasApiAccess: true })
  }

  // Remove empty AND
  if ((where.AND as unknown[]).length === 0) {
    delete where.AND
  }

  // Sort
  let orderBy: Record<string, unknown> = { rating: "desc" }
  switch (sort) {
    case "trending":
    case "views":
      orderBy = { viewCount: "desc" }
      break
    case "newest":
      orderBy = { createdAt: "desc" }
      break
    case "name":
      orderBy = { name: "asc" }
      break
    default:
      orderBy = { rating: "desc" }
  }

  const [tools, categories, categoryCounts] = await Promise.all([
    prisma.aITool.findMany({
      where,
      orderBy,
      include: {
        _count: { select: { reviews: { where: { status: "APPROVED" } } } },
      },
    }),
    prisma.aITool.groupBy({ by: ["category"], _count: { id: true }, orderBy: { _count: { id: "desc" } } }),
    prisma.aITool.count(),
  ])

  // Sponsored tools float to top when filter is active (or always show first)
  const sponsoredTools = tools.filter((t) => t.sponsored)
  const regularTools = tools.filter((t) => !t.sponsored)
  const sortedTools = [...sponsoredTools, ...regularTools]

  // Build compare URL helper
  const compareBase = `/ai-tools?q=${encodeURIComponent(q ?? "")}&sort=${sort ?? ""}`
  const buildFilterUrl = (overrides: Record<string, string | undefined>) => {
    const params = new URLSearchParams()
    if (q) params.set("q", q)
    if (sort) params.set("sort", sort)
    const merged = { category, pricingType, platform, hasFreeTrial, hasApiAccess, compare: compareSlugs.join(","), ...overrides }
    for (const [k, v] of Object.entries(merged)) {
      if (v && v !== "false" && v !== "") params.set(k, v)
    }
    return `/ai-tools?${params.toString()}`
  }

  return (
    <div className="space-y-8">
      <div>
        <h1 className="text-4xl font-bold tracking-tight">AI Tools Directory</h1>
        <p className="mt-2 text-lg text-muted-foreground">
          {categoryCounts} tools AI untuk produktivitas dan kreativitas Anda.
        </p>
      </div>

      <AdSlot section="tools_list" className="rounded-xl border p-4" />

      {/* Search + Sort Row */}
      <form method="GET" className="flex flex-col gap-3 md:flex-row">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
          <Input placeholder="Cari tools AI..." className="pl-10" name="q" defaultValue={q} />
        </div>
        {/* Sort dropdown */}
        <select
          name="sort"
          defaultValue={sort ?? "rating"}
          className="h-10 rounded-md border bg-background px-3 text-sm"
          onChange={(e) => {
            const form = e.target.closest("form")!
            const url = new URL(form.action)
            url.searchParams.set("sort", e.target.value)
            if (q) url.searchParams.set("q", q)
            if (category) url.searchParams.set("category", category)
            if (pricingType) url.searchParams.set("pricingType", pricingType)
            if (platform) url.searchParams.set("platform", platform)
            if (hasFreeTrial) url.searchParams.set("hasFreeTrial", hasFreeTrial)
            if (hasApiAccess) url.searchParams.set("hasApiAccess", hasApiAccess)
            window.location.href = url.toString()
          }}
        >
          {SORT_OPTIONS.map((opt) => (
            <option key={opt.value} value={opt.value}>{opt.label}</option>
          ))}
        </select>
        <input type="hidden" name="compare" value={compareSlugs.join(",")} />
        <Button type="submit" variant="default">Search</Button>
      </form>

      {/* Filter Row */}
      <div className="space-y-3">
        <div className="flex items-center gap-2 text-sm font-medium text-muted-foreground">
          <SlidersHorizontal className="h-4 w-4" />
          Filter:
        </div>

        {/* Category chips */}
        <div className="flex flex-wrap gap-2">
          <Link href={buildFilterUrl({ category: undefined })}>
            <Badge variant={!category ? "default" : "outline"} className="cursor-pointer">All</Badge>
          </Link>
          {categories.map((cat) => (
            <Link key={cat.category} href={buildFilterUrl({ category: cat.category })}>
              <Badge variant={category === cat.category ? "default" : "outline"} className="cursor-pointer hover:bg-primary/10">
                {cat.category} ({cat._count.id})
              </Badge>
            </Link>
          ))}
        </div>

        {/* Pricing Type chips */}
        <div className="flex flex-wrap gap-2">
          {PRICING_TYPES.map((pt) => (
            <Link key={pt.value} href={buildFilterUrl({ pricingType: pricingType === pt.value ? undefined : pt.value })}>
              <Badge variant={pricingType === pt.value ? "default" : "outline"} className="cursor-pointer">
                {pt.label}
              </Badge>
            </Link>
          ))}
        </div>

        {/* Feature toggles */}
        <div className="flex flex-wrap gap-2">
          <Link href={buildFilterUrl({ hasFreeTrial: hasFreeTrial === "true" ? undefined : "true" })}>
            <Badge variant={hasFreeTrial === "true" ? "default" : "outline"} className="cursor-pointer">
              🎁 Free Trial
            </Badge>
          </Link>
          <Link href={buildFilterUrl({ hasApiAccess: hasApiAccess === "true" ? undefined : "true" })}>
            <Badge variant={hasApiAccess === "true" ? "default" : "outline"} className="cursor-pointer">
              🔌 API Access
            </Badge>
          </Link>
          {PLATFORM_OPTIONS.map((pf) => (
            <Link key={pf} href={buildFilterUrl({ platform: platform === pf ? undefined : pf })}>
              <Badge variant={platform === pf ? "default" : "outline"} className="cursor-pointer capitalize">
                {pf}
              </Badge>
            </Link>
          ))}
        </div>

        {/* Active filter summary */}
        {(category || pricingType || platform || hasFreeTrial || hasApiAccess) && (
          <div className="flex flex-wrap items-center gap-2 text-sm">
            <span className="text-muted-foreground">Active:</span>
            {category && <Badge variant="secondary">{category} <Link href={buildFilterUrl({ category: undefined })} className="ml-1">×</Link></Badge>}
            {pricingType && <Badge variant="secondary">{pricingType} <Link href={buildFilterUrl({ pricingType: undefined })} className="ml-1">×</Link></Badge>}
            {platform && <Badge variant="secondary">{platform} <Link href={buildFilterUrl({ platform: undefined })} className="ml-1">×</Link></Badge>}
            {hasFreeTrial === "true" && <Badge variant="secondary">Free Trial <Link href={buildFilterUrl({ hasFreeTrial: undefined })} className="ml-1">×</Link></Badge>}
            {hasApiAccess === "true" && <Badge variant="secondary">API Access <Link href={buildFilterUrl({ hasApiAccess: undefined })} className="ml-1">×</Link></Badge>}
            <Link href={`/ai-tools?q=${encodeURIComponent(q ?? "")}`} className="text-xs text-muted-foreground hover:text-primary ml-2">
              Clear all
            </Link>
          </div>
        )}
      </div>

      {/* Compare Selection Bar */}
      {compareSlugs.length > 0 && (
        <div className="sticky top-16 z-40 rounded-xl border bg-background/95 p-4 shadow-md backdrop-blur">
          <div className="flex items-center justify-between gap-4">
            <div className="flex items-center gap-3">
              <div className="flex h-8 w-8 items-center justify-center rounded-full bg-primary text-primary-foreground">
                <GitCompare className="h-4 w-4" />
              </div>
              <div>
                <p className="text-sm font-medium">
                  Compare Queue ({compareSlugs.length}{maxCompare < 999 ? `/${maxCompare}` : ""})
                </p>
                <p className="text-xs text-muted-foreground line-clamp-1">
                  {compareSlugs.join(" • ")}
                </p>
              </div>
            </div>
            <div className="flex gap-2">
              {compareSlugs.length >= 2 && (
                <Link
                  href={`/ai-tools/compare?slugs=${compareSlugs.join(",")}`}
                  className="inline-flex h-9 items-center justify-center rounded-md bg-primary px-4 text-sm font-medium text-primary-foreground hover:bg-primary/90"
                >
                  Compare {compareSlugs.length} Tools
                </Link>
              )}
              <Link
                href={`/ai-tools?q=${encodeURIComponent(q ?? "")}`}
                className="inline-flex h-9 items-center justify-center rounded-md border px-3 text-sm font-medium hover:bg-muted"
              >
                <X className="h-4 w-4" />
              </Link>
            </div>
          </div>
        </div>
      )}

      {/* Results */}
      {sortedTools.length > 0 ? (
        <div className="grid gap-6 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
          {sortedTools.map((tool, idx) => {
            const isInCompare = compareSlugs.includes(tool.slug)
            const isNew = !tool.sponsored && idx < 3 && tool.createdAt > new Date(Date.now() - 7 * 24 * 60 * 60 * 1000)
            const nextCompare = isInCompare
              ? compareSlugs.filter((s) => s !== tool.slug)
              : [...compareSlugs, tool.slug]
            const reviewCount = tool._count?.reviews ?? 0

            return (
              <Card
                key={tool.id}
                className={`relative flex h-full flex-col transition-colors hover:border-primary ${isInCompare ? "ring-2 ring-primary" : ""}`}
              >
                {isInCompare && (
                  <div className="absolute -top-2 -right-2 z-10 flex h-6 w-6 items-center justify-center rounded-full bg-primary text-xs font-bold text-primary-foreground">
                    {compareSlugs.indexOf(tool.slug) + 1}
                  </div>
                )}

                {/* Sponsored badge */}
                {tool.sponsored && (
                  <div className="absolute -top-2 left-3 z-10 flex items-center gap-1 rounded-full bg-amber-500 px-2 py-0.5 text-xs font-bold text-white">
                    <Zap className="h-3 w-3" /> Sponsored
                  </div>
                )}

                <CardHeader className="relative">
                  <div className="mb-2 flex items-start justify-between gap-2">
                    <Badge variant="secondary">{tool.category}</Badge>
                    <div className="flex items-center gap-1 text-sm font-bold text-amber-500">
                      <Star className="h-4 w-4 fill-current" />
                      {tool.rating > 0 ? tool.rating.toFixed(1) : "—"}
                      {reviewCount > 0 && <span className="text-xs text-muted-foreground">({reviewCount})</span>}
                    </div>
                  </div>
                  <div className="flex flex-wrap gap-1">
                    {tool.sponsored && <Badge variant="outline" className="border-amber-500 text-amber-500">Featured</Badge>}
                    {tool.featured && !tool.sponsored && <Badge>Featured</Badge>}
                    {isNew && <Badge variant="outline">New</Badge>}
                    {tool.pricingType === "FREE" && <Badge variant="outline" className="border-green-500 text-green-500">Free</Badge>}
                    {tool.pricingType === "FREEMIUM" && <Badge variant="outline" className="border-blue-500 text-blue-500">Freemium</Badge>}
                    {tool.hasFreeTrial && <Badge variant="outline">🎁 Trial</Badge>}
                    {tool.hasApiAccess && <Badge variant="outline">🔌 API</Badge>}
                  </div>
                  <CardTitle className="line-clamp-2 leading-tight">{tool.name}</CardTitle>
                  <CardDescription className="line-clamp-2">{tool.tagline}</CardDescription>
                </CardHeader>

                <CardContent className="flex flex-1 flex-col justify-end gap-3">
                  <div className="flex items-center justify-between">
                    <Badge variant="outline">{tool.pricing}</Badge>
                    <div className="flex items-center gap-2">
                      {tool.viewCount > 0 && (
                        <span className="flex items-center gap-1 text-xs text-muted-foreground">
                          <TrendingUp className="h-3 w-3" />{tool.viewCount.toLocaleString()}
                        </span>
                      )}
                      <Link href={`/ai-tools/${tool.slug}`} className="text-xs font-medium text-primary hover:underline">
                        Detail →
                      </Link>
                    </div>
                  </div>

                  {/* Compare action */}
                  {isInCompare ? (
                    <Link
                      href={buildFilterUrl({ compare: nextCompare.join(",") })}
                      className="inline-flex h-8 items-center justify-center rounded-md border border-red-200 bg-red-50 px-3 text-xs font-medium text-red-600 hover:bg-red-100 dark:border-red-900 dark:bg-red-950 dark:text-red-400"
                    >
                      Remove from Compare
                    </Link>
                  ) : compareSlugs.length < maxCompare ? (
                    <Link
                      href={buildFilterUrl({ compare: nextCompare.join(",") })}
                      className="inline-flex h-8 items-center justify-center rounded-md border px-3 text-xs font-medium hover:bg-muted"
                    >
                      + Compare
                    </Link>
                  ) : null}
                </CardContent>
              </Card>
            )
          })}
        </div>
      ) : (
        <div className="rounded-lg border bg-muted/20 py-20 text-center">
          <p className="text-muted-foreground">Tidak ada tools AI yang cocok dengan filter Anda.</p>
          <Link href="/ai-tools" className="mt-3 inline-block text-sm text-primary hover:underline">
            Reset filters
          </Link>
        </div>
      )}

      <InternalLinksBlock />
    </div>
  )
}

