export const dynamic = "force-dynamic"

interface AirdropLinkMap {
  website?: string
  twitter?: string
  discord?: string
}

interface AirdropStep {
  title: string
  description?: string
  isOptional?: boolean
}

interface RiskScoreData {
  score: number
  level: "LOW" | "MEDIUM" | "HIGH" | "SCAM"
  factors: Record<string, any>
  analyzedAt: string
}

export async function generateStaticParams() {
  return []
