export default async function AirdropDetailPage({
  params,
}: {
  params: Promise<{ slug: string }>
}) {
  const { slug } = await params

  const airdrop = await prisma.airdrop.findUnique({
    where: { slug },
    include: {
      riskScore: true,
    },
  })

  if (!airdrop) {
    notFound()
  }

  const related = await prisma.airdrop.findMany({
    where: {
      slug: { not: airdrop.slug },
      OR: [{ network: airdrop.network }, { difficulty: airdrop.difficulty }],
    },
    take: 3,
    orderBy: { updatedAt: "desc" },
    select: { name: true, slug: true, network: true, status: true },
  })

  const socialLinks = (airdrop.links ?? {}) as AirdropLinkMap
  const steps = ((airdrop.steps ?? []) as unknown) as AirdropStep[]
  const statusVariant = airdrop.status === "ACTIVE" ? "default" : "secondary"

  // Convert riskScore to a format suitable for the client component
  const existingRiskScore: RiskScoreData | null = airdrop.riskScore
    ? {
        score: airdrop.riskScore.score,
        level: (airdrop.riskLevel as "LOW" | "MEDIUM" | "HIGH" | "SCAM") || "LOW",
        factors: airdrop.riskScore.factors as Record<string, any>,
        analyzedAt: airdrop.riskScore.analyzedAt.toISOString(),
      }
    : null

  return (
    <div className="mx-auto max-w-4xl space-y-10 py-8">
      <div className="flex flex-col items-start gap-8 md:flex-row">
        <div className="flex h-24 w-24 shrink-0 items-center justify-center rounded-2xl bg-muted text-4xl font-bold">
          {airdrop.name[0]}
        </div>
        <div className="flex-1 space-y-4">
          <div className="flex flex-wrap gap-2">
            <Badge variant="outline">{airdrop.network}</Badge>
            <Badge variant={statusVariant}>{airdrop.status}</Badge>
            <Badge variant="outline">Difficulty: {airdrop.difficulty}</Badge>
            {airdrop.riskLevel && (
              <Badge
                variant={
                  airdrop.riskLevel === "LOW"
                    ? "default"
                    : airdrop.riskLevel === "MEDIUM"
                      ? "secondary"
                      : "destructive"
                }
              >
                {airdrop.riskLevel} Risk
              </Badge>
            )}
          </div>
          <h1 className="text-4xl font-bold">{airdrop.name}</h1>
          <p className="text-xl font-semibold text-primary">
            Est. Reward: {airdrop.estimatedReward ?? "TBA"}
          </p>
          <div className="flex gap-4">
            {socialLinks.website && (
              <a
                href={socialLinks.website}
                target="_blank"
                rel="noopener noreferrer"
                className="text-muted-foreground hover:text-primary"
              >
                <Globe className="h-5 w-5" />
              </a>
            )}
            {socialLinks.twitter && (
              <a
                href={socialLinks.twitter}
                target="_blank"
                rel="noopener noreferrer"
                className="text-muted-foreground hover:text-primary"
              >
                <X className="h-5 w-5" />
              </a>
            )}
            {socialLinks.discord && (
              <a
                href={socialLinks.discord}
                target="_blank"
                rel="noopener noreferrer"
                className="text-muted-foreground hover:text-primary"
              >
                <Discord className="h-5 w-5" />
              </a>
            )}
          </div>
        </div>
      </div>

      <Separator />

      <div className="grid grid-cols-1 gap-12 lg:grid-cols-3">
        <div className="space-y-8 lg:col-span-2">
          <div className="prose prose-zinc max-w-none dark:prose-invert">
            <MDXRemote source={airdrop.content} components={components} />
          </div>

          {steps.length > 0 && (
            <div className="space-y-6">
              <h2 className="text-2xl font-bold">Step-by-Step Guide</h2>
              <StepTracker airdropSlug={airdrop.slug} steps={steps} />
            </div>
          )}

          {/* Reviews Section */}
          <ReviewsSection
            airdropId={airdrop.id}
            isLoggedIn={false}
          />

          {related.length > 0 && (
            <div className="space-y-4 rounded-xl border p-6">
              <h3 className="font-bold">Related Airdrops</h3>
              <div className="grid gap-3 sm:grid-cols-2">
                {related.map((item) => (
                  <Link
                    key={item.slug}
                    href={`/airdrop/${item.slug}`}
                    className="rounded-md border p-3 transition-colors hover:border-primary"
                  >
                    <p className="font-medium">{item.name}</p>
                    <p className="text-xs text-muted-foreground">
                      {item.network} · {item.status}
                    </p>
                  </Link>
                ))}
              </div>
            </div>
          )}
        </div>

        <div className="space-y-6">
          {/* Live Price Section */}
          <PriceDisplay network={airdrop.network} airdropId={airdrop.id} />

          {/* Risk Analysis Panel */}
          <RiskAnalysisPanel
            airdropId={airdrop.id}
            initialRiskLevel={airdrop.riskLevel}
            existingScore={existingRiskScore}
          />

          <div className="space-y-4 rounded-xl border p-6">
            <h3 className="font-bold">Requirements Checklist</h3>
            <RequirementsChecklist
              slug={airdrop.slug}
              requirements={airdrop.requirements}
            />
          </div>
          <ReportIssueForm slug={airdrop.slug} />
        </div>
      </div>
    </div>
  )
}

import { Metadata } from "next"
import { prisma } from "@/lib/prisma"
import { Badge } from "@/components/ui/badge"
import { CalendarView } from "@/components/airdrop/calendar-view"
import { Bell, Clock, TrendingUp } from "lucide-react"
import Link from "next/link"

export const dynamic = "force-dynamic"

interface SearchParams {
  network?: string
  filter?: string
}

interface PageProps {
  searchParams: Promise<SearchParams>
}

export async function generateMetadata(): Promise<Metadata> {
  const now = new Date()
  const futureDate = new Date(now.getTime() + 90 * 24 * 60 * 60 * 1000)

  const upcomingCount = await prisma.airdrop.count({
    where: {
      deadline: {
        gte: now,
        lte: futureDate,
      },
    },
  })

  return {
    title: "Airdrop Calendar — AI3",
    description: `Track upcoming crypto airdrops with deadlines. ${upcomingCount} airdrops with upcoming deadlines in the next 90 days.`,
    keywords: ["airdrop calendar", "crypto airdrops", "airdrop deadlines", "airdrop tracker"],
  }
}

export default async function AirdropCalendarPage({ searchParams }: PageProps) {
  const params = await searchParams
  const networkFilter = params.network || "all"
  const timeFilter = params.filter || "all"

  const now = new Date()
  const futureDate = new Date(now.getTime() + 365 * 24 * 60 * 60 * 1000)

  // Build where clause
  const where: any = {
    deadline: {
      gte: now,
      lte: futureDate,
    },
  }

  if (networkFilter !== "all") {
    where.network = networkFilter
  }

  // Get all unique networks for filter
  const networks = await prisma.airdrop.findMany({
    where: { network: { not: "" } },
    select: { network: true },
    distinct: ["network"],
  })

  // Fetch airdrops with deadlines
  const airdrops = await prisma.airdrop.findMany({
    where,
    orderBy: { deadline: "asc" },
    select: {
      id: true,
      name: true,
      slug: true,
      logo: true,
      network: true,
      status: true,
      estimatedReward: true,
      difficulty: true,
      deadline: true,
    },
  })

  // Group by month
  const groupedByMonth: Record<string, typeof airdrops> = {}

  for (const airdrop of airdrops) {
    if (!airdrop.deadline) continue

    const date = new Date(airdrop.deadline)
    const monthLabel = date.toLocaleDateString("en-US", { month: "long", year: "numeric" })

    if (!groupedByMonth[monthLabel]) {
      groupedByMonth[monthLabel] = []
    }
    groupedByMonth[monthLabel].push(airdrop)
  }

  // Calculate stats
  const thisWeek = airdrops.filter((a) => {
    if (!a.deadline) return false
    const daysLeft = Math.ceil((a.deadline.getTime() - now.getTime()) / (1000 * 60 * 60 * 24))
    return daysLeft <= 7 && daysLeft >= 0
  }).length

  const thisMonth = airdrops.filter((a) => {
    if (!a.deadline) return false
    const daysLeft = Math.ceil((a.deadline.getTime() - now.getTime()) / (1000 * 60 * 60 * 24))
    return daysLeft <= 30 && daysLeft >= 0
  }).length

  // JSON-LD Event structured data
  const jsonLdEvents = airdrops
    .filter((a) => a.deadline)
    .map((airdrop) => ({
      "@context": "https://schema.org",
      "@type": "Event",
      name: `${airdrop.name} Airdrop Deadline`,
      description: `Deadline to claim ${airdrop.name} airdrop on ${airdrop.network}`,
      startDate: airdrop.deadline?.toISOString(),
      eventStatus: "https://schema.org/EventScheduled",
      eventAttendanceMode: "https://schema.org/OnlineEventAttendanceMode",
      location: {
        "@type": "VirtualLocation",
        url: `/airdrop/${airdrop.slug}`,
      },
    }))

  return (
    <div className="container mx-auto py-8 space-y-8">
      {/* JSON-LD */}
      <script
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(jsonLdEvents) }}
      />

      {/* Header */}
      <div className="space-y-4">
        <div className="flex items-center gap-3">
          <Clock className="h-8 w-8 text-primary" />
          <h1 className="text-4xl font-bold">Airdrop Calendar</h1>
        </div>
        <p className="text-xl text-muted-foreground">
          Track upcoming airdrop deadlines and never miss an opportunity
        </p>
      </div>

      {/* Stats Cards */}
      <div className="grid gap-4 md:grid-cols-3">
        <div className="rounded-xl border bg-card p-6">
          <div className="flex items-center gap-3">
            <div className="rounded-lg bg-primary/10 p-3">
              <TrendingUp className="h-6 w-6 text-primary" />
            </div>
            <div>
              <p className="text-2xl font-bold">{airdrops.length}</p>
              <p className="text-sm text-muted-foreground">Total Upcoming</p>
            </div>
          </div>
        </div>
        <div className="rounded-xl border bg-card p-6">
          <div className="flex items-center gap-3">
            <div className="rounded-lg bg-red-500/10 p-3">
              <Clock className="h-6 w-6 text-red-500" />
            </div>
            <div>
              <p className="text-2xl font-bold">{thisWeek}</p>
              <p className="text-sm text-muted-foreground">This Week</p>
            </div>
