        </div>
      ) : (
        <div className="space-y-8">
          {sortedKeys.map((key) => (
            <section key={key} className="space-y-4">
              <h2 className="text-xl font-bold tracking-tight">{key}</h2>
              <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
