                          Edit
                        </Link>
                        <Link href={`/admin/posts/preview/${post.id}`} className="inline-flex h-7 items-center rounded-md border px-2 text-xs font-medium">
                          Preview
                        </Link>
                        <Link href={`/admin/posts/${post.id}/revisions`} className="inline-flex h-7 items-center rounded-md border px-2 text-xs font-medium">
                          History
                        </Link>
                      </div>

                      {/* Status action buttons */}
                      {canModerate && (
                        <div className="flex flex-wrap gap-1">
                          {post.status === "DRAFT" && (
                            <form action={submitForReviewAction}>
                              <input type="hidden" name="id" value={post.id} />
                              <Button type="submit" variant="outline" size="sm" className="h-7 text-xs">
                                Submit Review
                              </Button>
                            </form>
                          )}
                          {post.status === "PENDING_REVIEW" && (
                            <form action={approvePostAction}>
                              <input type="hidden" name="id" value={post.id} />
                              <Button type="submit" variant="default" size="sm" className="h-7 text-xs">
                                Approve
                              </Button>
                            </form>
                          )}
                          {(post.status === "APPROVED" || post.status === "PENDING_REVIEW") && (
                            <form action={publishPostAction}>
                              <input type="hidden" name="id" value={post.id} />
                              <Button type="submit" variant="default" size="sm" className="h-7 text-xs">
                                Publish
                              </Button>
                            </form>
                          )}
                          {post.status !== "ARCHIVED" && (
                            <form action={archivePostAction}>
                              <input type="hidden" name="id" value={post.id} />
                              <Button type="submit" variant="destructive" size="sm" className="h-7 text-xs">
                                Archive
                              </Button>
                            </form>
                          )}
                        </div>
                      )}

                      <form action={deletePostAction}>
                        <input type="hidden" name="id" value={post.id} />
                        <Button type="submit" variant="destructive" size="sm" className="h-7 text-xs w-full">
                          Delete
                        </Button>
                      </form>
                    </div>
                  </td>
                </tr>
              )
            })}
            {posts.length === 0 && (
              <tr>
                <td colSpan={8} className="px-4 py-10 text-center text-muted-foreground">
                  Belum ada post{statusFilter !== "ALL" ? ` dengan status "${STATUS_LABELS[statusFilter]?.label ?? statusFilter}"` : ""}.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex items-center justify-center gap-2">
          {currentPage > 1 && (
            <Link href={`/admin/posts?status=${statusFilter}&page=${currentPage - 1}`}>
              <Button variant="outline" size="sm">Previous</Button>
            </Link>
          )}
          <span className="text-sm text-muted-foreground">
            Page {currentPage} of {totalPages}
          </span>
          {currentPage < totalPages && (
            <Link href={`/admin/posts?status=${statusFilter}&page=${currentPage + 1}`}>
              <Button variant="outline" size="sm">Next</Button>
            </Link>
          )}
        </div>
      )}
    </div>
  )
}

"use client"

import { useState, useTransition } from "react"
import Link from "next/link"
import { Button } from "@/components/ui/button"
import type { ImportedToolData, BulkImportResult } from "../actions"

type Tab = "url" | "bulk"

type UrlPreview = ImportedToolData & { url: string; error?: string }

function slugify(input: string) {
  return input
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9\s-]/g, "")
    .replace(/\s+/g, "-")
    .replace(/-+/g, "-")
}

export default function ImportToolsPage() {
  const [tab, setTab] = useState<Tab>("url")
  const [isPending, startTransition] = useTransition()

  // URL Import state
  const [urlInput, setUrlInput] = useState("")
  const [urlPreviews, setUrlPreviews] = useState<UrlPreview[]>([])
  const [urlErrors, setUrlErrors] = useState<string[]>([])
  const [importResult, setImportResult] = useState<BulkImportResult | null>(null)

  // Bulk Import state
  const [bulkInput, setBulkInput] = useState("")
  const [bulkParsed, setBulkParsed] = useState<ImportedToolData[]>([])
  const [bulkErrors, setBulkErrors] = useState<string[]>([])
  const [bulkImportResult, setBulkImportResult] = useState<BulkImportResult | null>(null)

  const fetchUrlPreviews = () => {
    const urls = urlInput
      .split("\n")
      .map((u) => u.trim())
      .filter((u) => u.length > 0)

    if (urls.length === 0) {
      setUrlErrors(["Please enter at least one URL"])
      return
    }

    setUrlPreviews([])
    setUrlErrors([])
    setImportResult(null)

    const results: UrlPreview[] = []
    let completed = 0

    urls.forEach((url) => {
      startTransition(async () => {
        try {
          const res = await fetch("/api/tools/import-from-url", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ url }),
          })
          const data = await res.json()

          if (data.error) {
            results.push({ url, name: "", slug: "", error: data.error })
          } else {
            results.push({ url, ...data })
          }
        } catch (e: unknown) {
          const msg = e instanceof Error ? e.message : "Failed to fetch"
          results.push({ url, name: "", slug: "", error: msg })
        }

        completed++
        if (completed === urls.length) {
          setUrlPreviews(results)
        }
      })
    })
  }

  const importUrlPreviews = () => {
    const valid = urlPreviews.filter((p) => !p.error && p.name)
    if (valid.length === 0) return

    startTransition(async () => {
      const tools = valid.map((p) => ({
        name: p.name,
        slug: p.slug,
        tagline: p.tagline ?? undefined,
        description: p.description ?? undefined,
        pricing: p.pricing,
        category: p.category,
        websiteUrl: p.websiteUrl ?? undefined,
        affiliateUrl: p.affiliateUrl ?? undefined,
      }))

      const res = await fetch("/api/tools/bulk", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ tools }),
      })
      const data: BulkImportResult = await res.json()
      setImportResult(data)
    })
  }

  const parseBulkInput = () => {
    setBulkParsed([])
    setBulkErrors([])
    setBulkImportResult(null)

    const raw = bulkInput.trim()
    if (!raw) {
      setBulkErrors(["Please enter data to import"])
      return
    }

    let parsed: unknown

    // Try JSON first
    if (raw.startsWith("[")) {
      try {
        parsed = JSON.parse(raw)
      } catch {
        setBulkErrors(["Invalid JSON format. Please check your input."])
        return
      }
    } else {
      // Try CSV: name,slug,tagline,description,pricing,category,websiteUrl,affiliateUrl
      const lines = raw.split("\n").filter((l) => l.trim())
      if (lines.length === 0) {
        setBulkErrors(["No data found"])
        return
      }

      const tools: Array<{
        name: string
        slug?: string
        tagline?: string
        description?: string
        pricing?: string
        category?: string
        websiteUrl?: string
        affiliateUrl?: string
      }> = []

      for (const line of lines) {
        const fields = line.split(",").map((f) => f.trim().replace(/^["']|["']$/g, ""))
        if (fields.length < 1 || !fields[0]) continue
        tools.push({
          name: fields[0] || "",
          slug: fields[1] || undefined,
          tagline: fields[2] || undefined,
          description: fields[3] || undefined,
          pricing: fields[4] || undefined,
          category: fields[5] || undefined,
          websiteUrl: fields[6] || undefined,
          affiliateUrl: fields[7] || undefined,
        })
      }

