interface Props {
  params: Promise<{ username: string }>
}

export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const { username } = await params
  const user = await prisma.user.findUnique({
    where: { username },
    select: { name: true, username: true, image: true, bio: true },
  })

  if (!user) return { title: "User Not Found" }

  return generateSeo({
    title: `${user.name ?? user.username} (@${user.username})`,
    description: user.bio ?? `Profil ${user.name ?? user.username} di Web3AI Hub.`,
    type: "profile",
    canonical: `/profile/${username}`,
  })
}

export default async function UserProfilePage({ params }: Props) {
  const { username } = await params

  const user = await prisma.user.findUnique({
    where: { username },
    select: {
      id: true,
      username: true,
      name: true,
      image: true,
      bio: true,
      twitter: true,
      github: true,
      linkedin: true,
      telegram: true,
      role: true,
      createdAt: true,
      xp: {
        select: {
          totalXp: true,
          level: true,
        },
      },
      streak: {
        select: {
          currentStreak: true,
          longestStreak: true,
        },
      },
      achievements: {
        select: {
          id: true,
          earnedAt: true,
          xpAwarded: true,
          achievement: {
            select: {
              slug: true,
              name: true,
              description: true,
              icon: true,
              tier: true,
              xpReward: true,
            },
          },
        },
        orderBy: {
          earnedAt: "desc",
        },
      },
      posts: {
        where: { published: true },
        select: {
          id: true,
          title: true,
          slug: true,
          publishedAt: true,
          category: true,
        },
        orderBy: { publishedAt: "desc" },
        take: 5,
      },
      _count: {
        select: {
          posts: { where: { published: true } },
          achievements: true,
        },
      },
    },
  })

  if (!user) notFound()

  const totalXp = user.xp?.totalXp ?? 0
  const level = user.xp?.level ?? 1
  const currentStreak = user.streak?.currentStreak ?? 0
  const longestStreak = user.streak?.longestStreak ?? 0

  // Calculate XP progress to next level
  const xpForCurrentLevel = (level - 1) * 1000
  const xpForNextLevel = level * 1000
  const xpProgress = totalXp - xpForCurrentLevel
  const xpNeeded = xpForNextLevel - xpForCurrentLevel
  const progressPercent = Math.min(100, Math.round((xpProgress / xpNeeded) * 100))

  const tierColors: Record<string, string> = {
    BRONZE: "bg-amber-700",
