  safe: "border-l-green-500",
  warning: "border-l-yellow-500",
  danger: "border-l-red-500",
  ended: "border-l-gray-400",
}

function getDeadlineColor(deadline: Date | string | null, status: string): string {
  if (status === "ENDED") return deadlineColors.ended
  if (!deadline) return deadlineColors.safe

  const now = new Date()
  const deadlineDate = new Date(deadline)
  const daysLeft = Math.ceil((deadlineDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24))

  if (daysLeft < 0) return deadlineColors.ended
  if (daysLeft < 7) return deadlineColors.danger
  if (daysLeft < 30) return deadlineColors.warning
  return deadlineColors.safe
}

function getDaysRemaining(deadline: Date | string | null): string {
  if (!deadline) return "No deadline"

  const now = new Date()
  const deadlineDate = new Date(deadline)
  const daysLeft = Math.ceil((deadlineDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24))

  if (daysLeft < 0) return "Ended"
  if (daysLeft === 0) return "Today!"
  if (daysLeft === 1) return "1 day left"
  return `${daysLeft} days left`
}

function getDeadlineBadgeVariant(deadline: Date | string | null, status: string): "default" | "secondary" | "destructive" {
  if (status === "ENDED") return "secondary"
  if (!deadline) return "default"

  const now = new Date()
  const deadlineDate = new Date(deadline)
  const daysLeft = Math.ceil((deadlineDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24))

  if (daysLeft < 0) return "secondary"
  if (daysLeft < 7) return "destructive"
  return "default"
}

function formatDeadline(deadline: Date | string | null): string {
  if (!deadline) return "No deadline set"

  const date = new Date(deadline)
  return date.toLocaleDateString("en-US", {
    weekday: "long",
    year: "numeric",
    month: "long",
    day: "numeric",
  })
}

export function CalendarView({ airdrops, groupedByMonth }: CalendarViewProps) {
  const monthOrder = Object.keys(groupedByMonth).sort((a, b) => {
    const dateA = new Date(a)
    const dateB = new Date(b)
    return dateA.getTime() - dateB.getTime()
  })

  return (
    <div className="space-y-8">
      {monthOrder.map((month) => (
        <div key={month} className="space-y-4">
          <h2 className="text-xl font-semibold sticky top-16 z-10 bg-background py-2">
            {month}
          </h2>

          <div className="relative">
            {/* Timeline line */}
            <div className="absolute left-6 top-0 bottom-0 w-px bg-border" />

            <div className="space-y-3">
              {groupedByMonth[month].map((airdrop) => {
                const deadlineColor = getDeadlineColor(airdrop.deadline, airdrop.status)
                const daysRemaining = getDaysRemaining(airdrop.deadline)
                const badgeVariant = getDeadlineBadgeVariant(airdrop.deadline, airdrop.status)
                const formattedDeadline = formatDeadline(airdrop.deadline)

                return (
                  <Link
                    key={airdrop.id}
                    href={`/airdrop/${airdrop.slug}`}
                    className={cn(
                      "relative flex gap-4 rounded-lg border bg-card p-4 transition-all hover:shadow-md hover:border-primary/50",
                      "border-l-4",
                      deadlineColor
                    )}
                  >
                    {/* Timeline dot */}
                    <div className="absolute -left-[21px] top-1/2 -translate-y-1/2 h-3 w-3 rounded-full border-2 border-background bg-primary" />

                    {/* Logo placeholder */}
                    <div className="flex h-12 w-12 shrink-0 items-center justify-center rounded-lg bg-muted text-lg font-bold">
                      {airdrop.logo ? (
                        <img
                          src={airdrop.logo}
                          alt={airdrop.name}
                          className="h-full w-full object-contain rounded-lg"
                        />
                      ) : (
                        airdrop.name[0]
                      )}
                    </div>

                    {/* Content */}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-start justify-between gap-2">
                        <div>
                          <h3 className="font-semibold">{airdrop.name}</h3>
                          <div className="flex flex-wrap items-center gap-2 mt-1">
                            <Badge variant="outline" className="text-xs">
                              {airdrop.network}
                            </Badge>
                            <Badge
                              variant={badgeVariant}
                              className={cn("text-xs", statusColors[airdrop.status as keyof typeof statusColors])}
                            >
                              {airdrop.status}
                            </Badge>
                          </div>
                        </div>

                        <div className="text-right shrink-0">
                          <p className={cn(
                            "text-sm font-medium",
                            badgeVariant === "destructive" && "text-red-500",
                            badgeVariant === "default" && "text-green-600",
                            badgeVariant === "secondary" && "text-muted-foreground"
                          )}>
                            {daysRemaining}
                          </p>
                          <p className="text-xs text-muted-foreground mt-0.5">
                            {formattedDeadline}
                          </p>
                        </div>
                      </div>

                      {/* Estimated reward */}
                      {airdrop.estimatedReward && (
                        <p className="text-sm text-muted-foreground mt-2">
                          Est. Reward: <span className="text-primary font-medium">{airdrop.estimatedReward}</span>
                        </p>
                      )}
                    </div>
                  </Link>
                )
              })}
            </div>
          </div>
        </div>
      ))}
    </div>
  )
}

"use client"

import { useState, useEffect, useRef } from "react"
import { Bell, Check, Loader2, ExternalLink } from "lucide-react"
import { Badge } from "@/components/ui/badge"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import { cn } from "@/lib/utils"
import Link from "next/link"

interface Notification {
  id: string
  title: string
  message: string
  type: string
  isRead: boolean
  createdAt: string
  airdropId?: string
}

interface NotificationBellProps {
  userId?: string
}

export function NotificationBell({ userId }: NotificationBellProps) {
  const [notifications, setNotifications] = useState<Notification[]>([])
  const [unreadCount, setUnreadCount] = useState(0)
  const [loading, setLoading] = useState(false)
  const [open, setOpen] = useState(false)
  const dropdownRef = useRef<HTMLDivElement>(null)

  // Fetch notifications
  async function fetchNotifications() {
    if (!userId) return

    try {
      const res = await fetch("/api/notifications", {
        headers: { "x-user-id": userId },
      })

      if (res.ok) {
        const data = await res.json()
        setNotifications(data.notifications.slice(0, 5)) // Latest 5
        setUnreadCount(data.unreadCount)
      }
    } catch (error) {
      console.error("Failed to fetch notifications:", error)
    }
  }

  // Poll for new notifications every 60 seconds
  useEffect(() => {
    if (!userId) return

    fetchNotifications()

    const interval = setInterval(fetchNotifications, 60000)
    return () => clearInterval(interval)
  }, [userId])

  // Mark single notification as read
  async function markAsRead(notificationId: string) {
    try {
      const res = await fetch(`/api/notifications/${notificationId}/read`, {
        method: "POST",
        headers: { "x-user-id": userId || "" },
      })

      if (res.ok) {
        setNotifications((prev) =>
          prev.map((n) =>
            n.id === notificationId ? { ...n, isRead: true } : n
          )
        )
        setUnreadCount((prev) => Math.max(0, prev - 1))
      }
    } catch (error) {
      console.error("Failed to mark as read:", error)
    }
  }

  // Mark all as read
  async function markAllAsRead() {
    if (!userId || notifications.length === 0) return

    setLoading(true)
    try {
      const unreadIds = notifications.filter((n) => !n.isRead).map((n) => n.id)

      const res = await fetch("/api/notifications", {
        method: "PATCH",
        headers: {
          "Content-Type": "application/json",
          "x-user-id": userId,
        },
        body: JSON.stringify({ ids: unreadIds }),
      })

      if (res.ok) {
        setNotifications((prev) => prev.map((n) => ({ ...n, isRead: true })))
        setUnreadCount(0)
      }
    } catch (error) {
      console.error("Failed to mark all as read:", error)
    } finally {
      setLoading(false)
    }
  }

  // Close dropdown when clicking outside
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setOpen(false)
      }
    }

    if (open) {
      document.addEventListener("mousedown", handleClickOutside)
    }

    return () => {
      document.removeEventListener("mousedown", handleClickOutside)
    }
  }, [open])

  function formatTimeAgo(dateString: string): string {
    const date = new Date(dateString)
    const now = new Date()
    const seconds = Math.floor((now.getTime() - date.getTime()) / 1000)

    if (seconds < 60) return "just now"
    if (seconds < 3600) return `${Math.floor(seconds / 60)}m ago`
    if (seconds < 86400) return `${Math.floor(seconds / 3600)}h ago`
    return `${Math.floor(seconds / 86400)}d ago`
  }

  const typeColors: Record<string, string> = {
    deadline: "bg-red-500/10 text-red-600",
    reminder: "bg-yellow-500/10 text-yellow-600",
    update: "bg-blue-500/10 text-blue-600",
    xp_earned: "bg-green-500/10 text-green-600",
  }

  if (!userId) {
    return null
  }

  return (
    <DropdownMenu open={open} onOpenChange={setOpen}>
      <DropdownMenuTrigger className="relative flex h-10 w-10 items-center justify-center rounded-lg text-muted-foreground hover:bg-muted hover:text-foreground transition-colors">
        <Bell className="h-5 w-5" />
        {unreadCount > 0 && (
          <span className="absolute -right-1 -top-1 flex h-5 w-5 items-center justify-center rounded-full bg-red-500 text-xs text-white">
            {unreadCount > 9 ? "9+" : unreadCount}
          </span>
        )}
      </DropdownMenuTrigger>

      <DropdownMenuContent align="end" className="w-80" ref={dropdownRef}>
        <div className="flex items-center justify-between px-4 py-2 border-b">
          <span className="font-semibold">Notifications</span>
          {unreadCount > 0 && (
            <button
              onClick={markAllAsRead}
              disabled={loading}
              className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground disabled:opacity-50"
            >
              {loading ? (
                <Loader2 className="h-3 w-3 animate-spin" />
              ) : (
                <>
                  <Check className="h-3 w-3" />
                  Mark all read
                </>
              )}
            </button>
          )}
        </div>

        <div className="max-h-96 overflow-y-auto">
          {notifications.length === 0 ? (
            <div className="px-4 py-8 text-center text-muted-foreground">
              <Bell className="h-8 w-8 mx-auto mb-2 opacity-50" />
              <p className="text-sm">No notifications yet</p>
            </div>
          ) : (
            notifications.map((notification) => (
              <DropdownMenuItem
                key={notification.id}
                className={cn(
                  "px-4 py-3 cursor-pointer flex flex-col items-start gap-1",
                  !notification.isRead && "bg-muted/50"
                )}
                onClick={() => {
                  if (!notification.isRead) {
                    markAsRead(notification.id)
                  }
                }}
              >
                <div className="flex items-center gap-2 w-full">
                  <p className={cn("text-sm flex-1", !notification.isRead && "font-medium")}>
                    {notification.title}
                  </p>
                  <Badge
                    variant="outline"
                    className={cn("text-xs px-1 py-0", typeColors[notification.type])}
                  >
                    {notification.type}
                  </Badge>
                </div>
                <p className="text-xs text-muted-foreground w-full line-clamp-2">
                  {notification.message}
                </p>
                <p className="text-xs text-muted-foreground">
                  {formatTimeAgo(notification.createdAt)}
                </p>
                {!notification.isRead && (
                  <div className="h-2 w-2 rounded-full bg-primary mt-1" />
                )}
              </DropdownMenuItem>
            ))
          )}
        </div>

        {notifications.length > 0 && (
          <div className="border-t px-4 py-2">
            <Link
              href="/notifications"
              className="flex items-center justify-center gap-2 text-sm text-primary hover:underline"
              onClick={() => setOpen(false)}
            >
              View all notifications
              <ExternalLink className="h-3 w-3" />
            </Link>
          </div>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  )
}

"use client"

import { useEffect, useState } from "react"
import { Badge } from "@/components/ui/badge"
import { Skeleton } from "@/components/ui/skeleton"
import { TrendingUp, TrendingDown, DollarSign } from "lucide-react"

interface PriceData {
  usd: number
  change24h: number
  marketCap: number
  lastUpdated: string
}

interface PriceDisplayProps {
  network: string
  airdropId?: string
}

export function PriceDisplay({ network, airdropId }: PriceDisplayProps) {
  const [priceData, setPriceData] = useState<PriceData | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    async function fetchPrice() {
      setLoading(true)
      setError(null)

      try {
        const params = airdropId
          ? `?airdropIds=${airdropId}`
          : `?ids=${network.toLowerCase()}`

        const res = await fetch(`/api/airdrop/price${params}`)
        if (!res.ok) throw new Error("Failed to fetch")

        const data = await res.json()
        const networkKey = network.toLowerCase()
        const price = data[networkKey] || data[networkKey.replace(" ", "-")]

        if (price) {
          setPriceData(price)
        } else {
          setError("Price not available")
        }
      } catch (err) {
        setError("Unable to load price")
      } finally {
        setLoading(false)
      }
    }

    fetchPrice()
    // Refresh every 5 minutes
    const interval = setInterval(fetchPrice, 5 * 60 * 1000)
    return () => clearInterval(interval)
  }, [network, airdropId])

  if (loading) {
    return (
      <div className="space-y-2 rounded-xl border p-4">
        <Skeleton className="h-4 w-24" />
        <Skeleton className="h-8 w-32" />
      </div>
    )
  }

  if (error || !priceData) {
    return (
      <div className="rounded-xl border p-4">
        <div className="flex items-center gap-2 text-sm text-muted-foreground">
          <DollarSign className="h-4 w-4" />
          <span>Price data unavailable</span>
        </div>
      </div>
    )
  }

  const isPositive = priceData.change24h >= 0

  return (
    <div className="space-y-3 rounded-xl border p-4">
      <div className="flex items-center justify-between">
        <span className="text-sm font-medium text-muted-foreground">
          {network} Price
        </span>
        <Badge variant={isPositive ? "default" : "destructive"}>
          {isPositive ? (
            <TrendingUp className="h-3 w-3 mr-1" />
          ) : (
            <TrendingDown className="h-3 w-3 mr-1" />
          )}
          {Math.abs(priceData.change24h).toFixed(2)}%
        </Badge>
      </div>

      <div className="space-y-1">
        <p className="text-2xl font-bold">
          ${priceData.usd.toLocaleString(undefined, {
            minimumFractionDigits: 2,
            maximumFractionDigits: priceData.usd < 1 ? 6 : 2,
          })}
        </p>
        {priceData.marketCap > 0 && (
          <p className="text-xs text-muted-foreground">
            MCap: ${(priceData.marketCap / 1e9).toFixed(2)}B
          </p>
        )}
      </div>
    </div>
  )
}

"use client"

import { useEffect, useState } from "react"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { Skeleton } from "@/components/ui/skeleton"
import { Star, ThumbsUp, Loader2 } from "lucide-react"

interface ReviewUser {
  id: string
  name: string | null
  image: string | null
  username: string | null
}

interface Review {
  id: string
  rating: number
  comment: string | null
  helpful: number
  createdAt: string
  user: ReviewUser | null
}

interface ReviewsResponse {
  reviews: Review[]
  summary: {
    total: number
    average: number
    distribution: Record<number, number>
  }
}

interface ReviewsSectionProps {
  airdropId: string
  isLoggedIn?: boolean
  userId?: string
}

function StarRating({
  rating,
  onChange,
  interactive = false,
}: {
  rating: number
  onChange?: (rating: number) => void
  interactive?: boolean
}) {
  return (
    <div className="flex gap-1">
      {[1, 2, 3, 4, 5].map((star) => (
        <button
          key={star}
          type="button"
          disabled={!interactive}
          onClick={() => interactive && onChange?.(star)}
          className={`${interactive ? "cursor-pointer hover:scale-110" : "cursor-default"} transition-transform`}
        >
          <Star
            className={`h-5 w-5 ${
              star <= rating
                ? "fill-yellow-400 text-yellow-400"
                : "fill-muted text-muted-foreground"
            }`}
          />
        </button>
      ))}
    </div>
  )
}

function ReviewForm({
  airdropId,
  onSubmit,
  onCancel,
}: {
  airdropId: string
  onSubmit: () => void
  onCancel: () => void
}) {
  const [rating, setRating] = useState(0)
  const [comment, setComment] = useState("")
  const [submitting, setSubmitting] = useState(false)
  const [error, setError] = useState<string | null>(null)

  // For demo purposes, using a mock userId
  // In production, this should come from the session
  const userId = "demo-user"

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    if (rating === 0) {
      setError("Please select a rating")
      return
    }

    setSubmitting(true)
    setError(null)

    try {
      const res = await fetch(`/api/airdrop/${airdropId}/reviews`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ rating, comment, userId }),
      })

      if (!res.ok) {
        const data = await res.json()
        throw new Error(data.error || "Failed to submit review")
      }

      setRating(0)
      setComment("")
      onSubmit()
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to submit")
    } finally {
      setSubmitting(false)
    }
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-4 rounded-xl border p-4">
      <div className="space-y-2">
        <label className="text-sm font-medium">Your Rating</label>
        <StarRating rating={rating} onChange={setRating} interactive />
      </div>

      <div className="space-y-2">
        <label className="text-sm font-medium">Comment (optional)</label>
        <textarea
          value={comment}
          onChange={(e) => setComment(e.target.value)}
          placeholder="Share your experience with this airdrop..."
          rows={3}
          className="w-full rounded-lg border border-input bg-transparent px-3 py-2 text-sm transition-colors outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50 placeholder:text-muted-foreground"
        />
      </div>

      {error && <p className="text-sm text-destructive">{error}</p>}

      <div className="flex gap-2">
        <Button type="submit" disabled={submitting}>
          {submitting ? (
            <>
              <Loader2 className="h-4 w-4 mr-2 animate-spin" />
              Submitting...
            </>
          ) : (
            "Submit Review"
          )}
        </Button>
        <Button type="button" variant="outline" onClick={onCancel}>
          Cancel
        </Button>
      </div>
    </form>
  )
}

export function ReviewsSection({ airdropId, isLoggedIn = false, userId }: ReviewsSectionProps) {
  const [data, setData] = useState<ReviewsResponse | null>(null)
  const [loading, setLoading] = useState(true)
  const [showForm, setShowForm] = useState(false)
  const [votingId, setVotingId] = useState<string | null>(null)

  async function fetchReviews() {
    try {
      const res = await fetch(`/api/airdrop/${airdropId}/reviews`)
      if (res.ok) {
        const json = await res.json()
        setData(json)
      }
    } catch (err) {
      console.error("Failed to fetch reviews:", err)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    fetchReviews()
  }, [airdropId])

  async function voteHelpful(reviewId: string) {
    setVotingId(reviewId)
    try {
      const res = await fetch(`/api/airdrop/${airdropId}/reviews/${reviewId}/helpful`, {
        method: "POST",
      })
      if (res.ok) {
        // Refresh reviews to show updated count
        fetchReviews()
      }
    } catch (err) {
      console.error("Failed to vote:", err)
    } finally {
      setVotingId(null)
    }
  }

  if (loading) {
    return (
      <div className="space-y-4">
        <Skeleton className="h-6 w-32" />
        <Skeleton className="h-24 w-full" />
        <Skeleton className="h-24 w-full" />
      </div>
    )
  }

  const { reviews, summary } = data || { reviews: [], summary: { total: 0, average: 0, distribution: {} } }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold">Reviews ({summary.total})</h2>
        {isLoggedIn && !showForm && (
          <Button onClick={() => setShowForm(true)} variant="outline" size="sm">
            Write Review
          </Button>
        )}
      </div>

      {summary.total > 0 && (
        <div className="flex flex-wrap items-center gap-4 rounded-xl border p-4">
          <div className="text-center">
            <p className="text-3xl font-bold">{summary.average}</p>
            <StarRating rating={Math.round(summary.average)} />
            <p className="text-sm text-muted-foreground">{summary.total} reviews</p>
          </div>
          <div className="flex gap-4">
            {[5, 4, 3, 2, 1].map((star) => (
              <div key={star} className="flex items-center gap-2">
                <span className="text-sm text-muted-foreground">{star}</span>
                <Star className="h-4 w-4 fill-yellow-400 text-yellow-400" />
                <div className="w-20 h-2 rounded-full bg-muted overflow-hidden">
                  <div
                    className="h-full bg-yellow-400"
                    style={{
                      width: `${summary.total > 0 ? (summary.distribution[star] / summary.total) * 100 : 0}%`,
                    }}
                  />
                </div>
                <span className="text-sm text-muted-foreground">
                  {summary.distribution[star] || 0}
                </span>
              </div>
            ))}
          </div>
        </div>
      )}

      {showForm && (
        <ReviewForm
          airdropId={airdropId}
          onSubmit={() => {
            setShowForm(false)
            fetchReviews()
          }}
          onCancel={() => setShowForm(false)}
        />
      )}

      {reviews.length === 0 && !showForm && (
        <div className="rounded-xl border border-dashed p-8 text-center">
          <p className="text-muted-foreground">No reviews yet</p>
          {isLoggedIn && (
            <Button
              variant="link"
              onClick={() => setShowForm(true)}
              className="mt-2"
            >
              Be the first to write a review
            </Button>
          )}
        </div>
      )}

      <div className="space-y-4">
        {reviews.map((review) => (
          <div key={review.id} className="rounded-xl border p-4 space-y-3">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <div className="h-8 w-8 rounded-full bg-muted flex items-center justify-center text-sm font-medium">
                  {review.user?.name?.[0] || review.user?.username?.[0] || "?"}
                </div>
                <div>
                  <p className="font-medium">
                    {review.user?.name || review.user?.username || "Anonymous"}
                  </p>
                  <p className="text-xs text-muted-foreground">
                    {new Date(review.createdAt).toLocaleDateString()}
                  </p>
                </div>
              </div>
              <StarRating rating={review.rating} />
            </div>

            {review.comment && (
